passwd_str = read_file('/etc/passwd')
lines = passwd_str.split('\n')
for line in lines:
    if not line.strip():
        continue
    parts = line.split(':')
    if len(parts) < 6:
        continue
    try:
        uid = int(parts[2])
    except ValueError:
        continue
    home_dir = parts[5]
    if uid == 0 or uid >= 1000:
        init_file = home_dir + '/.INIT_FILE'
        try:
            read_file(init_file)
            run_cmd('chmod', '0740', init_file)
        except:
            pass
